import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as d,c as n,f as s,b as e,e as o,a as i,w as c,i as r}from"./app-d6a6dcfa.js";const p={},_=e("p",null,"Вся тема адаптивна, что означает, что она хорошо работает на разных размерах экрана.",-1),h=r('<h2 id="введение-в-адаптивныи-макет" tabindex="-1"><a class="header-anchor" href="#введение-в-адаптивныи-макет" aria-hidden="true">#</a> Введение в адаптивный макет</h2><p>На мобильных устройствах:</p><ul><li>На панели навигации имя сайта будет скрыто, а такие элементы, как ссылки панели навигации, переключатель тем и полноэкранная кнопка, будут свернуты в дополнительное всплывающее окно и переключаться с помощью кнопки в правой части панели навигации;</li><li>Боковая панель будет отображаться в виде бокового меню и скрыта по умолчанию, а кнопка переключения боковой панели отображается в левой части панели навигации для управления всплывающим окном и убиранием боковой панели;</li><li>Навигация по пути, основной текст, текст кнопки «Вверх» имеют меньший размер шрифта.</li><li>Заголовок текущей страницы свернут в боковую панель</li></ul><p>На планшетах/ноутбуках:</p><ul><li>Ссылки на панели навигации появятся в панели навигации</li><li>Боковая панель будет отображаться как сворачиваемое меню</li><li>Заголовок текущей страницы свернут в боковую панель</li></ul><p>На устройстве ПК:</p><ul><li>Ссылки на панели навигации появятся в панели навигации</li><li>Боковая панель будет прикрепляться к левой части контента на странице</li><li>Название текущей страницы будет отображаться в правой части страницы</li></ul><h2 id="отзывчивая-конфигурация" tabindex="-1"><a class="header-anchor" href="#отзывчивая-конфигурация" aria-hidden="true">#</a> Отзывчивая конфигурация</h2><p>Темы предоставляют переменные контрольные точки для управления адаптивным поведением макета. Вы можете изменить их в <code>.vuepress/styles/config.scss</code>:</p><ul><li><code>$pc</code>: Контрольная точка макета для ПК, по умолчанию <code>1440px</code></li><li><code>$laptop</code>: Контрольная точка адаптивного макета ноутбука, по умолчанию <code>1280px</code></li><li><code>$pad</code>: Контрольная точка макета, реагирующего на большую панель, по умолчанию <code>959px</code></li><li><code>$tablet</code>: Контрольная точка адаптивного макета планшета, по умолчанию <code>768px</code></li><li><code>$mobile</code>: Контрольная точка адаптивного макета для мобильных устройств, по умолчанию <code>480px</code></li></ul>',10),u=e("code",null,"$tablet",-1),m=e("code",null,"$pc",-1),f=e("code",null,"mobileBreakPoint",-1),x=e("code",null,"pcBreakPoint",-1);function b(k,$){const l=a("RouterLink");return d(),n("div",null,[_,s(" more "),h,e("p",null,[o("В частности, "),u,o(" и "),m,o(" будут основываться только на размере пикселя, если вы его измените, вам также необходимо установить "),i(l,{to:"/config/theme/appearance.html#mobilebreakpoint"},{default:c(()=>[f]),_:1}),o(" и "),i(l,{to:"/config/theme/appearance.html#mobilebreakpoint"},{default:c(()=>[x]),_:1}),o(" с измененным размером пикселя.")])])}const N=t(p,[["render",b],["__file","responsive.html.vue"]]);export{N as default};
